if (! function_exists('wikipedia_article')) {
    function wikipedia_article($title = null, $language = null, $mode = null, $query = null, $max_results = null, $timeout = null)
    {
            $title = $title ?? '';
            $language = $language ?? 'en';
            $mode = $mode ?? 'summary';
            $query = $query ?? '';
            $max_results = $max_results ?? 10;
            $timeout = $timeout ?? 15;

            $timeout = max(5, min(30, (int)$timeout));
            $max_results = max(1, min(25, (int)$max_results));
            $language = preg_replace('/[^a-z\-]/', '', strtolower(substr(trim($language), 0, 10)));
            if (empty($language)) $language = 'en';

            // Helper: fetch JSON
            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: wikipedia_article/1.0\r\nAccept: application/json\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status >= 400) return ['error' => "HTTP $status", 'status' => $status, 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            $rest_base = "https://{$language}.wikipedia.org/api/rest_v1";
            $action_base = "https://{$language}.wikipedia.org/w/api.php";

            // MODE: SEARCH
            if ($mode === 'search') {
                $q = trim($query);
                if (empty($q)) {
                    return ['success' => false, 'error' => 'Search query is required when mode=search.'];
                }
                $search_url = $action_base . '?action=query&list=search&srsearch=' . urlencode($q) . '&srlimit=' . $max_results . '&srinfo=totalhits&format=json';
                $result = $fetch_json($search_url, $timeout);
                if (!$result['success']) {
                    return ['success' => false, 'error' => 'Search failed: ' . $result['error']];
                }
                $search_data = $result['data'];
                $hits = $search_data['query']['searchinfo']['totalhits'] ?? 0;
                $results = $search_data['query']['search'] ?? [];

                $items = [];
                foreach ($results as $r) {
                    $snippet = strip_tags($r['snippet'] ?? '');
                    $items[] = [
                        'title' => $r['title'],
                        'page_id' => $r['pageid'] ?? 0,
                        'snippet' => mb_substr($snippet, 0, 200),
                        'word_count' => $r['wordcount'] ?? 0,
                        'timestamp' => $r['timestamp'] ?? '',
                    ];
                }

                return [
                    'success' => true,
                    'query' => $q,
                    'language' => $language,
                    'mode' => 'search',
                    'total_hits' => $hits,
                    'results_returned' => count($items),
                    'results' => $items,
                ];
            }

            // MODE: SUMMARY or FULL
            $article_title = trim($title);
            if (empty($article_title)) {
                return ['success' => false, 'error' => 'Article title is required. Use mode=search to find articles.'];
            }

            // Step 1: Fetch page summary from REST API
            $encoded_title = urlencode(str_replace(' ', '_', $article_title));
            $summary_url = "{$rest_base}/page/summary/{$encoded_title}";
            $summary_result = $fetch_json($summary_url, $timeout);

            if (!$summary_result['success']) {
                $status = $summary_result['status'] ?? 0;
                if ($status === 404) {
                    return [
                        'success' => false,
                        'error' => "Article not found: '$article_title'. Check spelling or use mode=search first.",
                        'language' => $language,
                        'title' => $article_title,
                    ];
                }
                return [
                    'success' => false,
                    'error' => 'Wikipedia API error: ' . $summary_result['error'],
                    'language' => $language,
                    'title' => $article_title,
                ];
            }

            $summary = $summary_result['data'];

            // Check for redirects / disambiguation
            $page_type = $summary['type'] ?? 'standard';

            // Basic fields from summary
            $result = [
                'success' => true,
                'language' => $language,
                'mode' => $mode,
                'title' => $summary['title'] ?? $article_title,
                'display_title' => $summary['displaytitle'] ?? $summary['title'] ?? '',
                'page_id' => $summary['pageid'] ?? null,
                'extract' => $summary['extract'] ?? '',
                'extract_html' => $summary['extract_html'] ?? '',
                'description' => $summary['description'] ?? '',
                'page_url' => $summary['content_urls']['desktop']['page'] ?? "https://{$language}.wikipedia.org/wiki/{$encoded_title}",
                'edit_url' => $summary['content_urls']['desktop']['edit'] ?? '',
                'page_type' => $page_type,
                'wikidata_id' => null,
            ];

            // Thumbnail image
            if (isset($summary['thumbnail'])) {
                $result['thumbnail'] = [
                    'url' => $summary['thumbnail']['source'] ?? '',
                    'width' => $summary['thumbnail']['width'] ?? 0,
                    'height' => $summary['thumbnail']['height'] ?? 0,
                ];
            }

            // Original image (might be larger)
            if (isset($summary['originalimage'])) {
                $result['original_image'] = [
                    'url' => $summary['originalimage']['source'] ?? '',
                    'width' => $summary['originalimage']['width'] ?? 0,
                    'height' => $summary['originalimage']['height'] ?? 0,
                ];
            }

            // Coordinates
            if (isset($summary['coordinates'])) {
                $result['coordinates'] = [
                    'lat' => $summary['coordinates'][0]['lat'] ?? null,
                    'lon' => $summary['coordinates'][0]['lon'] ?? null,
                ];
            }

            // Wikidata ID from REST summary
            // (not directly in the summary endpoint, need to parse)

            // Step 2: If mode=full, get more data from the Action API
            if ($mode === 'full') {
                $action_url = $action_base . '?action=query&prop=extracts|pageimages|coordinates|categories|pageprops|info|pageviews&titles=' . $encoded_title . '&exintro=1&explaintext=1&piprop=thumbnail|original&pithumbsize=400&cllimit=50&ppprop=wikibase_item&inprop=url&format=json';
                $action_result = $fetch_json($action_url, $timeout);

                if ($action_result['success']) {
                    $pages = $action_result['data']['query']['pages'] ?? [];
                    $page = reset($pages);

                    if ($page) {
                        // Wikidata ID
                        $result['wikidata_id'] = $page['pageprops']['wikibase_item'] ?? null;

                        // Categories
                        $categories = [];
                        if (isset($page['categories'])) {
                            foreach ($page['categories'] as $cat) {
                                $cats[] = str_replace('Category:', '', $cat['title']);
                            }
                            // Limit to reasonable number
                            $cats = array_slice($cats ?? [], 0, 30);
                            $result['categories'] = $cats;
                        }

                        // Page stats
                        $result['page_stats'] = [
                            'page_id' => $page['pageid'] ?? null,
                            'ns' => $page['ns'] ?? 0,
                            'touched' => $page['touched'] ?? '',
                            'last_rev_id' => $page['lastrevid'] ?? null,
                            'length' => $page['length'] ?? 0,
                        ];

                        // Page views (last 60 days - returned as daily counts)
                        if (isset($page['pageviews'])) {
                            $views = $page['pageviews'];
                            $total = array_sum($views);
                            $result['page_stats']['pageviews_60d'] = $total;
                            $result['page_stats']['pageviews_daily_avg'] = $total > 0 ? round($total / count($views)) : 0;
                        }
                    }
                }

                // Step 3: Fetch page HTML for richer content (optional)
                // Try to get the Wikidata ID from a different approach if not found
                if (!$result['wikidata_id']) {
                    $meta_url = $action_base . '?action=query&prop=pageprops&titles=' . $encoded_title . '&format=json';
                    $meta_result = $fetch_json($meta_url, $timeout);
                    if ($meta_result['success']) {
                        $meta_pages = $meta_result['data']['query']['pages'] ?? [];
                        $meta_page = reset($meta_pages);
                        if ($meta_page) {
                            $result['wikidata_id'] = $meta_page['pageprops']['wikibase_item'] ?? null;
                        }
                    }
                }
            }

            // Language links count (if available from extract)
            $result['extract_word_count'] = str_word_count(strip_tags($result['extract']) ?? '');

            return $result;
    }
